CREATE   PROC DQT_XUAT_PALLET_TU_DEXUAT
(
	@dexuat_id INT
)
AS
BEGIN
	BEGIN TRY
		BEGIN TRANSACTION;
		DECLARE @nguoitao NVARCHAR(200);
		DECLARE @ngaytao DATETIME = GETDATE();
		SELECT @nguoitao = nguoitao, @ngaytao = ngaytao FROM dqt_pallet_yeucauxuat WHERE id = @dexuat_id

		DECLARE @idXuat int;
		INSERT INTO dqt_xuat_pallet(bennhan, ngayxuat, ngaytao, nguoitao, ngaysua, nguoisua, active, dexuat_id, dondathang)
		SELECT bennhan, ngaydexuat, ngaytao, nguoitao, ngaysua, nguoisua, 1, id, dondathang FROM dqt_pallet_yeucauxuat WHERE id = @dexuat_id

		SET @idXuat = SCOPE_IDENTITY();

		DECLARE @id INT, @sophieu_pallet NVARCHAR(200), @sothanh_dexuat INT, @sokhoi_dexuat FLOAT
		DECLARE CUR CURSOR LOCAL FOR
			SELECT id, sophieu_pallet, sothanh_dexuat, sokhoi_dexuat
			FROM dqt_pallet_yeucauxuat_chitiet
			WHERE dexuat_id = @dexuat_id
		OPEN CUR
		FETCH NEXT FROM CUR INTO @id, @sophieu_pallet, @sothanh_dexuat, @sokhoi_dexuat
		WHILE @@FETCH_STATUS = 0
		BEGIN
			DECLARE @id1 UNIQUEIDENTIFIER;
			DECLARE @id_chitiet UNIQUEIDENTIFIER;
			DECLARE @nguyenlieu NVARCHAR(200);
			DECLARE @xuatxu INT;
			DECLARE @dayy FLOAT;
			DECLARE @rong FLOAT;
			DECLARE @dai FLOAT;

			SET @id1 = NEWID();
			SET @id_chitiet = NULL;
			SET @nguyenlieu = NULL;
			SET @xuatxu = NULL;
			SET @dayy = NULL;
			SET @rong = NULL;
			SET @dai = NULL;

			SELECT @id_chitiet = A.id, @xuatxu = A.xuatxu, @nguyenlieu = B.nguyenlieu, @dayy = A.dayy, @rong = A.rong, @dai = A.dai
			FROM dqt_pallet_chitiet A INNER JOIN tr_nguyenlieu_gva B ON A.id_nguyenlieu = B.id
			WHERE sophieu = @sophieu_pallet

			EXECUTE DQT_XUAT_PALLET_CHITIET_INSERT @id1, @idXuat, @id_chitiet, @nguyenlieu, @xuatxu, @dayy, @rong, @dai, @sothanh_dexuat, @sokhoi_dexuat;
	
			UPDATE dqt_pallet_yeucauxuat_chitiet
			SET nguoiduyet = @nguoitao, 
				ngayduyet = @ngaytao,
				daxuat = 1
			WHERE id = @id

			FETCH NEXT FROM CUR INTO @id, @sophieu_pallet, @sothanh_dexuat, @sokhoi_dexuat;
		END
		CLOSE CUR;
		DEALLOCATE CUR;

		COMMIT;
	END TRY
	BEGIN CATCH
		ROLLBACK;
	END CATCH
END
